create or replace function public.list_user_organizations()
returns table (
  org_id uuid,
  name text,
  slug text,
  role text,
  member_count integer,
  is_active_context boolean
)
language sql
stable
security definer
set search_path = public
as $$
  with my_orgs as (
    select om.org_id, om.role
    from public.org_members om
    where om.profile_id = auth.uid()
  ),
  active as (
    select active_org_id
    from public.profile_settings
    where profile_id = auth.uid()
    limit 1
  )
  select
    o.id as org_id,
    o.name,
    o.slug,
    mo.role,
    (select count(*)::int from public.org_members where org_id = o.id) as member_count,
    o.id = (select active_org_id from active) as is_active_context
  from my_orgs mo
  join public.organizations o on o.id = mo.org_id
  order by o.name;
$$;

create or replace function public.set_active_org_context(p_org_id uuid)
returns void
language plpgsql
security definer
set search_path = public
as $$
begin
  if auth.uid() is null then
    raise exception 'Authentication required';
  end if;

  if p_org_id is not null and not public.is_org_member(p_org_id) then
    raise exception 'Not a member of org %', p_org_id;
  end if;

  -- profile_settings is created lazily for some flows; ensure a row exists
  -- before updating so the setter is robust.
  insert into public.profile_settings (profile_id, active_org_id)
  values (auth.uid(), p_org_id)
  on conflict (profile_id) do update
    set active_org_id = excluded.active_org_id;
end;
$$;

-- Import a list of source documents (workspace or org-scoped) into a
-- project as link-only documents. Returns the created documents rows.
--
-- Authorization: caller must be able to write project content AND must
-- be able to read each source (RLS on workspace_documents / org_documents
-- already enforces this for the intermediate selects below, but we also
-- explicitly verify membership for clearer error messages).
create or replace function public.import_documents_to_project(
  p_project_id uuid,
  p_source_kind text,
  p_source_doc_ids uuid[]
)
returns setof public.documents
language plpgsql
security definer
set search_path = public
as $$
declare
  v_source_id uuid;
  v_inserted public.documents%rowtype;
  v_workspace_row public.workspace_documents%rowtype;
  v_org_row public.org_documents%rowtype;
begin
  if auth.uid() is null then
    raise exception 'Authentication required';
  end if;

  if not public.can_write_project_content(p_project_id) then
    raise exception 'Not authorized to add documents to project %', p_project_id;
  end if;

  if p_source_kind not in ('workspace', 'org') then
    raise exception 'Invalid source_kind: %', p_source_kind;
  end if;

  if p_source_doc_ids is null or array_length(p_source_doc_ids, 1) is null then
    return;
  end if;

  foreach v_source_id in array p_source_doc_ids loop
    if p_source_kind = 'workspace' then
      select *
      into v_workspace_row
      from public.workspace_documents
      where id = v_source_id
        and owner_profile_id = auth.uid();

      if not found then
        raise exception 'Workspace document % not accessible', v_source_id;
      end if;

      insert into public.documents (
        project_id,
        type,
        title,
        origin,
        description,
        created_by,
        linked_external_kind,
        linked_workspace_document_id
      )
      values (
        p_project_id,
        coalesce(v_workspace_row.type, 'knowledge_base'),
        v_workspace_row.title,
        'manual',
        v_workspace_row.description,
        auth.uid(),
        'workspace',
        v_source_id
      )
      returning * into v_inserted;
      return next v_inserted;
    else
      select *
      into v_org_row
      from public.org_documents
      where id = v_source_id
        and public.is_org_member(org_id);

      if not found then
        raise exception 'Org document % not accessible', v_source_id;
      end if;

      insert into public.documents (
        project_id,
        type,
        title,
        origin,
        description,
        created_by,
        linked_external_kind,
        linked_org_document_id
      )
      values (
        p_project_id,
        coalesce(v_org_row.type, 'knowledge_base'),
        v_org_row.title,
        'manual',
        v_org_row.description,
        auth.uid(),
        'org',
        v_source_id
      )
      returning * into v_inserted;
      return next v_inserted;
    end if;
  end loop;

  return;
end;
$$;

